// Normalize offer data from different networks
const offers = $input.all();
const normalizedOffers = [];

for (const offer of offers) {
  const data = offer.json;
  const network = offer.json._network || 'unknown';

  // Extract common fields based on network
  let normalized = {
    network: network,
    raw_data: data,
    extracted_at: new Date().toISOString()
  };

  switch(network) {
    case 'impact_radius':
      normalized = {
        ...normalized,
        offer_id: data.CampaignId,
        advertiser: data.AdvertiserName,
        name: data.CampaignName,
        description: data.Description,
        category: data.Category,
        commission_type: data.CommissionType,
        commission_rate: data.DefaultCommission,
        cookie_duration: data.CookieDuration,
        status: data.Status,
        tracking_url: data.TrackingLink,
        terms_url: data.TermsAndConditions
      };
      break;

    case 'shareasale':
      normalized = {
        ...normalized,
        offer_id: data.merchantId,
        advertiser: data.merchantname,
        name: data.merchantname,
        description: data.description,
        category: data.category,
        commission_type: 'percentage',
        commission_rate: data.commission,
        cookie_duration: data.cookielength,
        status: data.status,
        tracking_url: data.linkurl,
        terms_url: data.terms
      };
      break;

    case 'cj_affiliate':
      normalized = {
        ...normalized,
        offer_id: data.advertiserId,
        advertiser: data.advertiserName,
        name: data.advertiserName,
        description: data.description,
        category: data.category,
        commission_type: data.commissionType,
        commission_rate: data.commission,
        cookie_duration: data.cookieLength,
        status: data.status,
        tracking_url: data.trackingUrl,
        terms_url: data.termsUrl
      };
      break;
  }

  normalizedOffers.push(normalized);
}

return normalizedOffers;

// Score offers based on multiple criteria
const offers = $input.all();
const scoredOffers = [];

for (const offer of offers) {
  const score = calculateOfferScore(offer.json);

  scoredOffers.push({
    ...offer.json,
    score: score.total,
    score_breakdown: score.breakdown,
    recommendation: getRecommendation(score.total),
    priority: getPriority(score.total)
  });
}

function calculateOfferScore(offer) {
  const breakdown = {
    commission_score: 0,
    relevance_score: 0,
    competition_score: 0,
    trust_score: 0,
    volume_score: 0
  };

  // Commission score (0-30 points)
  const commission = parseFloat(offer.commission_rate) || 0;
  breakdown.commission_score = Math.min(commission * 2, 30);

  // Relevance score based on category match (0-25 points)
  const targetCategories = $env.TARGET_CATEGORIES ? $env.TARGET_CATEGORIES.split(',') : [];
  if (targetCategories.includes(offer.category)) {
    breakdown.relevance_score = 25;
  } else if (offer.category && offer.category.length > 0) {
    breakdown.relevance_score = 15;
  } else {
    breakdown.relevance_score = 5;
  }

  // Competition score (0-20 points) - lower competition = higher score
  const competition = offer.competition_level || 'medium';
  switch(competition) {
    case 'low': breakdown.competition_score = 20; break;
    case 'medium': breakdown.competition_score = 12; break;
    case 'high': breakdown.competition_score = 5; break;
    default: breakdown.competition_score = 10;
  }

  // Trust score based on network and advertiser (0-15 points)
  const networkTrust = {
    'impact_radius': 8,
    'shareasale': 7,
    'cj_affiliate': 9,
    'rakuten': 8,
    'awin': 7
  };
  breakdown.trust_score = networkTrust[offer.network] || 5;

  // Volume score based on estimated traffic (0-10 points)
  const volume = offer.estimated_volume || 'low';
  switch(volume) {
    case 'high': breakdown.volume_score = 10; break;
    case 'medium': breakdown.volume_score = 7; break;
    case 'low': breakdown.volume_score = 3; break;
    default: breakdown.volume_score = 5;
  }

  const total = Object.values(breakdown).reduce((a, b) => a + b, 0);

  return {
    total: total,
    breakdown: breakdown
  };
}

function getRecommendation(score) {
  if (score >= 80) return 'highly_recommended';
  if (score >= 65) return 'recommended';
  if (score >= 50) return 'consider';
  return 'not_recommended';
}

function getPriority(score) {
  if (score >= 80) return 'p1_immediate';
  if (score >= 65) return 'p2_high';
  if (score >= 50) return 'p3_medium';
  return 'p4_low';
}

return scoredOffers;

