// Process approved offers and send to SIMP broker
const approvalData = $input.first().json;
const offer = approvalData.offer;
const decision = approvalData.decision;
const notes = approvalData.notes || '';

if (decision === 'approved') {
  // Send to SIMP broker for activation
  const activationPayload = {
    intent_type: 'offer_activation',
    source_agent: 'n8n_workflow',
    target_agent: 'base_media_agent',
    payload: {
      offer: offer,
      approved_at: new Date().toISOString(),
      approved_by: approvalData.approver || 'human',
      notes: notes
    }
  };

  return {
    json: {
      status: 'approved',
      offer_id: offer.offer_id,
      activation_payload: activationPayload,
      should_activate: true
    }
  };
} else {
  // Log rejection
  const rejectionPayload = {
    intent_type: 'offer_rejection',
    source_agent: 'n8n_workflow',
    target_agent: 'base_media_agent',
    payload: {
      offer: offer,
      rejected_at: new Date().toISOString(),
      reason: decision,
      notes: notes
    }
  };

  return {
    json: {
      status: 'rejected',
      offer_id: offer.offer_id,
      rejection_payload: rejectionPayload
    }
  };
}

// Generate discovery report
const allOffers = $input.all();
const stats = {
  timestamp: new Date().toISOString(),
  total_discovered: allOffers.length,
  high_scoring: allOffers.filter(o => o.json.score >= 80).length,
  recommended: allOffers.filter(o => o.json.score >= 65).length,
  by_network: {},
  by_category: {},
  top_offers: allOffers
    .map(o => ({
      name: o.json.name,
      network: o.json.network,
      score: o.json.score,
      commission: o.json.commission_rate,
      category: o.json.category
    }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 10)
};

// Group by network
for (const offer of allOffers) {
  const network = offer.json.network;
  if (!stats.by_network[network]) {
    stats.by_network[network] = 0;
  }
  stats.by_network[network]++;

  // Group by category
  const category = offer.json.category || 'uncategorized';
  if (!stats.by_category[category]) {
    stats.by_category[category] = 0;
  }
  stats.by_category[category]++;
}

// Send report to SIMP broker
const reportPayload = {
  intent_type: 'offer_discovery_report',
  source_agent: 'n8n_workflow',
  target_agent: 'base_media_agent',
  payload: stats
};

return {
  json: {
    report: stats,
    report_payload: reportPayload,
    should_send_report: true
  }
};
